external_knowledge:
- 'running low in stock' means the stock quantity is below the reorder level; 
- 'significantly high average sales' means an average sale total amount greater than 5000; 
- 'exceptionally large sales' means a sale total amount greater than 1000.

sql:
SELECT item_identifier
FROM inventory
WHERE stock_quantity <= reorder_level;

SELECT item_outlet_sales
  FROM sales
  WHERE item_identifier = '1';
